'use client'

import { Card } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { MapPin, AlertCircle, RefreshCw } from 'lucide-react'

interface GovProblemCardProps {
  id: string
  title: string
  description?: string
  location: string
  timestamp?: Date
  complaintId?: string
  occurrences?: number
  lastReportedAt?: Date
  category?: string
  severity?: 'low' | 'medium' | 'high'
  type?: 'new' | 'recurring'
}

const SEVERITY_COLORS = {
  low: 'bg-blue-900/20 text-blue-400',
  medium: 'bg-yellow-900/20 text-yellow-400',
  high: 'bg-red-900/20 text-red-400',
}

export default function GovProblemCard({
  id,
  title,
  description,
  location,
  timestamp,
  complaintId,
  occurrences,
  lastReportedAt,
  category,
  severity = 'medium',
  type = 'new',
}: GovProblemCardProps) {
  return (
    <Card className="bg-card border-border p-4 hover:border-accent/50 transition-colors">
      <div className="space-y-3">
        {/* Header with type indicator */}
        <div className="flex items-start justify-between gap-2">
          <h3 className="font-semibold text-foreground line-clamp-2 flex-1">{title}</h3>
          {type === 'recurring' && (
            <RefreshCw className="w-5 h-5 text-accent flex-shrink-0 mt-1" />
          )}
        </div>

        {/* Description */}
        {description && (
          <p className="text-sm text-muted-foreground line-clamp-2">{description}</p>
        )}

        {/* Location */}
        <div className="flex items-center gap-2 text-sm text-muted-foreground">
          <MapPin className="w-4 h-4 flex-shrink-0" />
          <span>{location}</span>
        </div>

        {/* IDs and metadata */}
        <div className="space-y-1 text-xs text-muted-foreground">
          {complaintId && (
            <div>Complaint ID: {complaintId}</div>
          )}
          {occurrences && (
            <div className="flex items-center gap-1">
              <AlertCircle className="w-3 h-3" />
              <span>{occurrences} occurrences reported</span>
            </div>
          )}
        </div>

        {/* Footer with badges */}
        <div className="flex flex-wrap items-center gap-2 pt-2 border-t border-border">
          {category && (
            <Badge variant="secondary" className="text-xs">
              {category}
            </Badge>
          )}
          {severity && (
            <Badge className={`text-xs ${SEVERITY_COLORS[severity]}`}>
              {severity.toUpperCase()}
            </Badge>
          )}
          <div className="text-xs text-muted-foreground ml-auto">
            {timestamp
              ? new Date(timestamp).toLocaleDateString()
              : lastReportedAt
              ? new Date(lastReportedAt).toLocaleDateString()
              : 'N/A'}
          </div>
        </div>
      </div>
    </Card>
  )
}
